const items = $input.all().map(i => i.json);
if (items.length === 0) return [];

const newItems = items.filter(i => i.status === 'new');
const activeItems = items.filter(i => i.status !== 'new' && i.status !== 'none');

const sections = [];

// 새 공유회
if (newItems.length > 0) {
  const lines = newItems.map(i => {
    const slug = (i.i_alimurl || '').split('/').pop() || 'unknown';
    const url = i.i_alimurl || 'https://selfishclub.xyz/sharing/' + slug;
    return '• *' + i.i_title_userside + '* — ' + (i.i_full_schedule || '') + '\n  👉 `CRM 시작해줘 ' + url + '`';
  }).join('\n\n');
  sections.push({ type:'header', text:{ type:'plain_text', text:'🆕 새 공유회 감지! (' + newItems.length + '개)' }});
  sections.push({ type:'section', text:{ type:'mrkdwn', text: lines }});
  sections.push({ type:'divider' });
}

// 오늘 타임라인
if (activeItems.length > 0) {
  const statusMap = { open:'🟢 오픈일', remind:'🔵 리마인드', d1:'🟡 D-1', dday:'🔴 D-day' };
  const ddayTimeline = '⏰ 13:00 ⑤할인쿠폰(미신청자)\n⏰ 14:00 ④당일리마인드(신청자)\n⏰ 19:00 ⑥입장링크(신청자)\n⏰ 20:00 ⑦라이브시작(신청자)\n⏰ 22:00 ⑧혜택안내(신청자)';
  const lines = activeItems.map(i => {
    let timeline = '';
    if (i.status === 'open') timeline = '⏰ 09:00 ①오픈알림(멤버십전체)';
    if (i.status === 'remind') timeline = '⏰ 10:00 ②오픈리마인드(미신청자)';
    if (i.status === 'd1') timeline = '⏰ 13:00 ③D-1리마인드(신청자)';
    if (i.status === 'dday') timeline = ddayTimeline;
    return (statusMap[i.status] || i.status) + ' *' + i.i_title_userside + '*\n' + timeline;
  }).join('\n\n');
  sections.push({ type:'header', text:{ type:'plain_text', text:'📋 오늘 알림톡 타임라인' }});
  sections.push({ type:'section', text:{ type:'mrkdwn', text: lines }});
  sections.push({ type:'context', elements:[{ type:'mrkdwn', text:'각 시간에 n8n 모달이 Slack으로 옵니다. 승인하면 발송됩니다.' }]});
}

if (sections.length === 0) return [];

const text = (newItems.length > 0 ? '새 공유회 ' + newItems.length + '개' : '') +
  (activeItems.length > 0 ? (newItems.length > 0 ? ' + ' : '') + '오늘 알림톡 ' + activeItems.length + '건' : '');

return [{ json: { channel:'C0AN2NZ4L7L', text, blocks: JSON.stringify(sections) }}];

